define half @select_fcmp_nnan_ogt_negzero(half %x) {
  %gtzero = fcmp nnan ogt half %x, 0xH8000
  %negx = fsub nnan half 0xH0000, %x
  %fabs = select i1 %gtzero, half %x, half %negx
  ret half %fabs
}

define fp128 @select_fcmp_nnan_ogt_zero(fp128 %x) {
  %gtzero = fcmp nnan ogt fp128 %x, 0xL00000000000000000000000000000000
  %negx = fsub nnan fp128 0xL00000000000000000000000000000000, %x
  %fabs = select i1 %gtzero, fp128 %x, fp128 %negx
  ret fp128 %fabs
}

define <2 x float> @select_fcmp_nnan_ole_negzero(<2 x float> %x) {
  %lezero = fcmp nnan ole <2 x float> %x, <float -0.000000e+00, float -0.000000e+00>
  %negx = fsub nnan <2 x float> <float 0.000000e+00, float poison>, %x
  %fabs = select <2 x i1> %lezero, <2 x float> %negx, <2 x float> %x
  ret <2 x float> %fabs
}

